from typing import List

class Solution:

    def find_pair(self, arr: List[int], target: int, result: List[int]) -> bool:
        for k in range(len(arr)):
            if arr[k] == target:
                result[0] = k
                return True
        return False

    def solve(self):
        n = int(input())
        arr = list(map(int, input().split()))
        target = int(input())
        result = [-1, -1]
        if self.find_pair(arr, target, result):
            print(result)
        else:
            print('[%d, %d]' % result)

    def main(self):
        self.solve()

if __name__ == '__main__':
    solution = Solution()
    solution.main()

solutions.cpp:
#include <iostream>
#include <vector>
using namespace std;

class Solution {
public:
bool findPair(int n, int arr[], int target, int &i, int &j) {
for (int k = 0; k < n; k++) {
if (arr[k] == target) {
i = k;
j = k;
return true;
}
}
return false;
}

bool solve(int n, int arr[], int target) {
int i, j;
return findPair(n, arr, target, i, j);
}

int main() {
int n, target;
cin >> n;
int* arr = new int[n];
for (int k = 0; k < n; k++)
cin >> arr[k];
cin >> target;
if (solve(n, arr, target))
	cout << '[' << arr[0] << ', ' << arr[1] << ']';
elsen
	cout << '[-1, -1]';
return 0;
}
